import "server-only";

import { Resend } from "resend";

export const resend = new Resend(process.env.RESEND_API_KEY);

import { Body, Button, Container, Head, Heading, Html, Preview, Text } from "@react-email/components";

export function WelcomeEmail({ name, actionUrl }: { name: string; actionUrl: string }) {
  return (
    <Html lang="en">
      <Head />
      <Preview>Welcome to your workspace</Preview>
      <Body style={{ background: "#ffffff", fontFamily: "sans-serif" }}>
        <Container>
          <Heading>Welcome, {name}</Heading>
          <Text>Your account is ready. Open the dashboard to finish setup.</Text>
          <Button href={actionUrl}>Open dashboard</Button>
        </Container>
      </Body>
    </Html>
  );
}

import { randomUUID } from "node:crypto";
import { NextResponse } from "next/server";

import { WelcomeEmail } from "@/emails/welcome-email";
import { resend } from "@/lib/resend/client";

export async function POST(request: Request) {
  let body: { email?: string; name?: string };

  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  if (!body.email) return NextResponse.json({ error: "email is required" }, { status: 400 });

  const result = await resend.emails.send({
    from: process.env.RESEND_FROM_EMAIL ?? "StackFoundry <onboarding@resend.dev>",
    to: [body.email],
    subject: "Welcome",
    react: WelcomeEmail({ name: body.name ?? "there", actionUrl: "/" }),
    headers: { "X-Entity-Ref-ID": randomUUID() },
  });

  return NextResponse.json(result);
}

const deployChecks = [
  "Create the provider project and add production env vars",
  "Run the included smoke route after deploy",
  "Document alerting, retries, and rollback behavior",
];

export default function ResendEmailPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Resend Email</h1>
        <p className="text-muted-foreground">Transactional email delivery with React Email templates and verified sender domains.</p>
      </div>
      <div className="grid gap-3">
        {deployChecks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
